import { useState } from 'react';

function Home() {
  // Estado para la posición del mouse
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // Función para capturar la posición del mouse
  const handleMouseMove = (e: any) => {
    const { clientX, clientY } = e;
    setMousePosition({ x: clientX, y: clientY });
  };

  // Calcular el desplazamiento dentro del radio de 10px
  const calculateTransform = (imageIndex: any) => {
    const { x, y } = mousePosition;

    // Obtener la posición de la imagen en el DOM
    const image = document.querySelector(`#image-${imageIndex}`);
    const rect: any = image?.getBoundingClientRect();
    const imageCenterX = rect?.left + rect?.width / 2;
    const imageCenterY = rect?.top + rect?.height / 2;

    // Calcular la distancia relativa desde el mouse hasta el centro de la imagen
    const distanceX = x - imageCenterX;
    const distanceY = y - imageCenterY;

    // Limitar el movimiento a un radio de 10px
    const moveDistance = Math.min(
      10,
      Math.sqrt(distanceX * distanceX + distanceY * distanceY)
    );

    // Calcular el ángulo de desplazamiento
    const angle = Math.atan2(distanceY, distanceX);

    // Desplazamiento dentro del radio de 10px
    const moveX = moveDistance * Math.cos(angle);
    const moveY = moveDistance * Math.sin(angle);

    return `translate(${moveX}px, ${moveY}px)`;
  };

  return (
    <div
      className="w-full h-[100vh] flex items-center justify-center p-10 relative"
      onMouseMove={handleMouseMove}
    >
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          opacity: 0.4,
        }}
      />
      <div className="w-full h-full z-10 flex items-center justify-between">
        {/* Images left */}
        <div className="h-full relative flex items-center">
          <div className="ml-40 relative">
            {/* Primera imagen */}
            <img
              id="image-1"
              className="rounded-lg transition-transform transform"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
              id="image-2"
              className="rounded-lg absolute transition-transform transform"
              width={150}
              height={150}
              style={{
                top: `calc(50% - 75px)`,
                left: `calc(-35%)`,
                transform: calculateTransform(2),
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            <img
              id="image-3"
              className="rounded-lg absolute transition-transform transform"
              width={150}
              height={150}
              style={{
                top: `calc(90%)`,
                left: `calc(50% - 75px)`,
                transform: calculateTransform(3),
              }}
              src="/Foto4.HEIC"
              alt="Imagen 3"
            />
          </div>
        </div>
        {/* Text center */}
        <div className="h-full flex flex-col justify-center items-center gap-5">
          <h3 className="text-[#6d7561] md:text-2xl font-medium text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-4xl md:text-4xl font-bold text-center">
            Anto & Kevin
          </h1>
          <a
            href="#ConfirmAttendance"
            className="text-[#6d7561] text-2xl underline hover:text-[#6d756190]"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>
        {/* Images right */}
        <div className="h-full relative flex items-center justify-end">
          <div className="mr-40 relative">
            <img
              className="rounded-lg transition-transform transform hover:scale-110"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
              className="rounded-lg absolute -right-28 transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{
                top: 'calc(50% - 75px)',
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
